"""Tests for log_parser.py, built against real logs generated by our own
compile sandbox (apps/compile) for an undefined-control-sequence error, a
runaway-argument/missing-brace error with no line number, an
undefined-reference warning, an Overfull \\hbox warning, a halt-on-error
single-error case, and (for the fix-it assistant) two real undefined-command
logs where the command name only appears on a following context line."""

from django.test import SimpleTestCase

from .log_parser import parse_log

